        var numNodes: Double = com.omnifret.gplayer.core.ecmaScript.Math.floor(childs.length / (2.0).toDouble())
        var numLeafs: Double = com.omnifret.gplayer.core.ecmaScript.Math.floor((numNodes + 1.0) / (2.0).toDouble())
        var overflow: Double = 0.0
        if (true) {
            var i: Double = 0.0
            
