                {
                    var bitLength: Double = lengths[(i).toInt()] + 1.0
                    if (bitLength > this._maxLength)
                    {
                        bitLength = this._maxLength
                        overflow++
                    }
                    lengths[(childs[((2.0).toDouble() * i).toInt()]).toInt()] = bitLength
                    lengths[(childs[((2.0).toDouble() * i + 1.0).toInt()]).toInt()] = bitLength
