                this._bitLengthCounts[(++incrBitLen).toInt()]++
                overflow -= 1 shl ((this._maxLength - (1.0).toDouble() - incrBitLen)).toInt()
            }
            while (overflow > 0 && incrBitLen < this._maxLength - (1.0).toDouble())
        }
        while (overflow > 0)
        this._bitLengthCounts[(this._maxLength - (1.0).toDouble()).toInt()] += overflow
        this._bitLengthCounts[(this._maxLength - (2.0).toDouble()).toInt()] -= overflow
        var nodePtr: Double = (2.0).toDouble() * numLeafs
        if (true) {
            var bits: Double = this._maxLength
            
            while(bits != 0.0){
                var n: Double = this._bitLengthCounts[(bits - (1.0).toDouble()).toInt()]
