    /**
     * Scan a literal or distance tree to determine the frequencies of the codes
     * in the bit length tree.
     */
    public fun calcBLFreq(blTree: com.omnifret.gplayer.zip.Tree): Unit{
        var maxCount: Double
        var minCount: Double
        var count: Double
        var curlen: Double = -1.0
        var i: Double = 0.0
        while (i < this.numCodes)
        {
            count = 1.0
            var nextlen: Double = this.length!![(i).toInt()]
            if (nextlen == 0.0)
            {
                maxCount = 138.0
                minCount = 3.0
            }
            else 
            {
                maxCount = 6.0
                minCount = 3.0
                if (curlen != nextlen)
                {
                    blTree.freqs[(nextlen).toInt()]++
                    count = 0.0
                }
            }
            curlen = nextlen
            i++
            while (i < this.numCodes && curlen == this.length!![(i).toInt()])
            {
                i++
                if (++count >= maxCount)
                {
                    break
                }
            }
            if (count < minCount)
            {
                blTree.freqs[(curlen).toInt()] += count
            }
            else if (curlen != 0.0)
            {
                blTree.freqs[(com.omnifret.gplayer.zip.Tree._repeat3To6).toInt()]++
            }
            else if (count <= 10)
            {
                blTree.freqs[(com.omnifret.gplayer.zip.Tree._repeat3To10).toInt()]++
            }
            else 
            {
                blTree.freqs[(com.omnifret.gplayer.zip.Tree._repeat11To138).toInt()]++
            }
        }
    }
    
