        var nextCode: com.omnifret.gplayer.core.ecmaScript.Int32Array = com.omnifret.gplayer.core.ecmaScript.Int32Array(this._maxLength)
        var code: Double = 0.0
        this._codes = com.omnifret.gplayer.core.ecmaScript.Int16Array(this.freqs.length)
        if (true) {
            var bits: Double = 0.0
            
            while(bits < this._maxLength){
                nextCode[(bits).toInt()] = code
                code += (this._bitLengthCounts[(bits).toInt()]).toInt() shl (((15.0).toDouble() - bits)).toInt()
                bits++
            }
        }
        if (true) {
            var i: Double = 0.0
            
            while(i < this.numCodes){
                var bits: Double = this.length!![(i).toInt()]
                if (bits > 0)
                {
                    this._codes!![(i).toInt()] = com.omnifret.gplayer.zip.DeflaterHuffman.bitReverse(nextCode[(bits - (1.0).toDouble()).toInt()])
                    nextCode[(bits - (1.0).toDouble()).toInt()] += 1 shl (((16.0).toDouble() - bits)).toInt()
                }
                i++
            }
        }
    }
    
    /**
     * Write tree values
     * @param blTree Tree to write
     */
    public fun writeTree(blTree: com.omnifret.gplayer.zip.Tree): Unit{
        var maxCount: Double
        var minCount: Double
        var count: Double
        var curlen: Double = -1.0
        var i: Double = 0.0
        while (i < this.numCodes)
        {
            count = 1.0
            var nextlen: Double = this.length!![(i).toInt()]
            if (nextlen == 0.0)
            {
                maxCount = 138.0
                minCount = 3.0
            }
            else 
            {
                maxCount = 6.0
                minCount = 3.0
                if (curlen != nextlen)
                {
                    blTree.writeSymbol(nextlen)
                    count = 0.0
                }
            }
            curlen = nextlen
            i++
            while (i < this.numCodes && curlen == this.length!![(i).toInt()])
            {
                i++
                if (++count >= maxCount)
                {
                    break
